mapper.select:
SELECT * FROM tb_account

    is_deleted = 0

        AND created_by = #{req.creatorId}


        AND user_id = #{req.userId}


        AND coin LIKE CONCAT('%', #{req.coin}, '%')


        AND amount >= #{req.amountMin}


        AND amount <= #{req.amountMax}


        AND created_at >= #{req.createdAtAfter}


        AND created_at <= #{req.createdAtBefore}


ORDER BY created_at DESC
